// Minimal HTMX implementation for Unbound (search support)
(function(){
  function init(){
    document.querySelectorAll('[hx-get]').forEach(function(el){
      var trigger = el.getAttribute('hx-trigger') || 'change';
      var target = el.getAttribute('hx-target');
      var indicator = el.getAttribute('hx-indicator');
      var triggers = trigger.split(',').map(function(t){ return t.trim().split(' ')[0]; });
      triggers.forEach(function(ev){
        el.addEventListener(ev, function(){
          var url = el.getAttribute('hx-get');
          var val = el.value || '';
          var sep = url.indexOf('?') >= 0 ? '&' : '?';
          var fullUrl = url + sep + 'q=' + encodeURIComponent(val);
          var targetEl = target ? document.querySelector(target) : el.parentNode;
          if(indicator){ var ind = document.querySelector(indicator); if(ind) ind.style.display='block'; }
          fetch(fullUrl, {headers:{'HX-Request':'true'}})
            .then(function(r){ return r.text(); })
            .then(function(html){
              if(targetEl) targetEl.innerHTML = html;
              if(indicator){ var ind = document.querySelector(indicator); if(ind) ind.style.display='none'; }
            })
            .catch(function(){ });
        });
      });
    });
  }
  if(document.readyState === 'loading'){
    document.addEventListener('DOMContentLoaded', init);
  } else { init(); }
})();
